
INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('clinical_guideline', 'thyroid_disorders', ARRAY['thyroid','hypothyroid','hyperthyroid','tsh','thyroxine','levothyroxine','goiter','thyroid function'], 'Thyroid Disorders Management', E'## Thyroid Disorders Guidelines\n\n**Hypothyroidism:**\n- TSH elevated, T4 low\n- Treatment: Levothyroxine\n  - Start: 25-50mcg daily (elderly/cardiac: 25mcg)\n  - Titrate every 6-8 weeks\n  - Target: TSH within normal range\n  - Take on empty stomach, 30 min before food\n- Pregnancy: increase dose by 25-50% immediately\n\n**Hyperthyroidism:**\n- TSH suppressed, T4/T3 elevated\n- Causes: Graves'', toxic nodule, thyroiditis\n- Treatment: Carbimazole 15-40mg daily → titrate\n- Beta-blocker (propranolol) for symptoms\n- Definitive: radioiodine or surgery\n\n**Monitoring:**\n- TFTs every 6-8 weeks until stable\n- Then every 6-12 months\n\n⚠️ **Carbimazole: warn about sore throat (agranulocytosis) — urgent FBC**', 'en', 'NICE/ATA', 6, true),

('clinical_guideline', 'depression_screening', ARRAY['depression','phq-9','mental health','screening','antidepressant','mood','sadness','suicide risk'], 'Depression Screening (PHQ-9)', E'## Depression Screening & Management\n\n**PHQ-9 Scoring:**\n- 0-4: Minimal\n- 5-9: Mild\n- 10-14: Moderate\n- 15-19: Moderately severe\n- 20-27: Severe\n\n**Management by severity:**\n- **Mild:** Active monitoring, self-help, exercise\n- **Moderate:** Low-intensity psychological therapy (CBT, guided self-help) ± SSRI\n- **Severe:** SSRI + high-intensity psychological therapy, consider referral\n\n**First-line SSRI:** Fluoxetine, sertraline, or citalopram\n- Start low, review at 2-4 weeks\n- Takes 4-6 weeks for effect\n- Continue 6+ months after remission\n\n**Safety netting:**\n- Always ask about suicidal ideation (Q9)\n- Safety plan if any risk\n- Crisis numbers\n\n⚠️ **Under-25s on SSRIs: monitor weekly for first 4 weeks (suicidality risk)**', 'en', 'NICE/WHO mhGAP', 6, true),

('clinical_guideline', 'pediatric_diarrhea', ARRAY['diarrhea','child','pediatric','dehydration','ors','zinc','rotavirus','gastroenteritis'], 'Pediatric Diarrhea Management', E'## Pediatric Diarrhea & ORS Guidelines\n\n**Assessment of dehydration:**\n- **None:** Normal activity, tears, moist mouth\n- **Some:** Restless, sunken eyes, drinks eagerly, reduced skin turgor\n- **Severe:** Lethargic, sunken eyes, unable to drink, very poor turgor\n\n**Treatment Plan A (no dehydration):**\n- Continue feeding/breastfeeding\n- Give extra fluids (ORS after each stool)\n- Zinc 20mg/day for 10-14 days (10mg if <6 months)\n\n**Treatment Plan B (some dehydration):**\n- ORS 75mL/kg over 4 hours\n- Reassess after 4 hours\n\n**Treatment Plan C (severe dehydration):**\n- IV Ringer''s lactate 30mL/kg in 30 min, then 70mL/kg in 2.5h\n- Or 100mL/kg over 3-6 hours\n\n**Red flags for referral:**\n- Bloody diarrhea, high fever, persistent vomiting\n- Age <2 months, severe malnutrition\n\n⚠️ **Do NOT use antidiarrheals in children — ORS + zinc is the standard of care**', 'en', 'WHO/IMCI', 6, true),

('clinical_guideline', 'malaria_treatment', ARRAY['malaria','plasmodium','fever','antimalarial','chloroquine','act','artemisinin','mosquito'], 'Malaria Treatment Guidelines', E'## Malaria Treatment Guidelines\n\n**Diagnosis:** Blood smear (thick/thin film) or rapid diagnostic test (RDT)\n\n**Uncomplicated P. falciparum:**\n- ACT: Artemether-lumefantrine (Coartem)\n  - Adult: 4 tablets at 0, 8, 24, 36, 48, 60h\n  - Take with fatty food for absorption\n  - 3-day course\n\n**Severe malaria (any of: impaired consciousness, prostration, seizures, acidosis, hypoglycemia, severe anemia, renal failure, jaundice, pulmonary edema):**\n- IV artesunate 2.4mg/kg at 0, 12, 24h then daily\n- Switch to oral ACT when able to tolerate\n- IV quinine if artesunate unavailable\n\n**P. vivax/ovale:**\n- ACT or chloroquine (where still sensitive)\n- Add primaquine 14 days (radical cure — check G6PD first!)\n\n**Prevention:** Chemoprophylaxis for travelers, ITNs, IRS\n\n⚠️ **Check G6PD before primaquine — risk of hemolytic anemia**', 'en', 'WHO', 6, true),

('clinical_guideline', 'tb_screening', ARRAY['tuberculosis','tb','cough','weight loss','night sweats','sputum','afb','rifampicin','isoniazid'], 'TB Screening & Treatment', E'## TB Screening & Treatment Guidelines\n\n**Suspect active TB if:**\n- Cough >2 weeks + any of:\n  - Weight loss, night sweats, fever\n  - Hemoptysis, lymphadenopathy\n  - Contact with TB case\n\n**Diagnosis:**\n- Sputum AFB smear (×3, including early morning)\n- GeneXpert MTB/RIF (rapid, detects resistance)\n- CXR: upper lobe infiltrates, cavitation\n- Mantoux/TST or IGRA for latent TB\n\n**Treatment (new cases):**\n- Intensive phase (2 months): RHZE\n  - Rifampicin + Isoniazid + Pyrazinamide + Ethambutol\n- Continuation phase (4 months): RH\n  - Rifampicin + Isoniazid\n- DOT (Directly Observed Therapy) recommended\n\n**Monitoring:**\n- Sputum at 2, 5, 6 months\n- LFTs if symptomatic\n- Visual acuity (ethambutol)\n- Pyridoxine 10mg daily with isoniazid (prevent neuropathy)\n\n⚠️ **Rifampicin turns body fluids orange — warn patients. Reduces OCP efficacy.**', 'en', 'WHO/NICE', 6, true),

('clinical_guideline', 'hiv_pep', ARRAY['hiv','pep','post-exposure prophylaxis','needlestick','sexual exposure','antiretroviral','art'], 'HIV Post-Exposure Prophylaxis', E'## HIV PEP Guidelines\n\n**Indications:**\n- Needlestick injury from known/suspected HIV+ source\n- Sexual assault\n- Unprotected sex with HIV+ partner\n- Sharing injection equipment\n\n**Timing:** Start within 72 hours (ideally within 1-2 hours)\n\n**Regimen (28 days):**\n- TDF/FTC (Truvada) + Dolutegravir 50mg daily\n- Alternative: TDF/FTC + Raltegravir 400mg BD\n\n**Baseline testing:**\n- HIV test (ensure recipient is HIV-negative)\n- Hepatitis B and C\n- Renal function, pregnancy test\n- Source patient: rapid HIV test\n\n**Follow-up:**\n- HIV test at 6 weeks, 3 months, 6 months\n- Adherence support (side effects common)\n- Hepatitis B vaccination if not immune\n\n**Side effects:** Nausea, fatigue, headache (usually resolve in 1-2 weeks)\n\n⚠️ **PEP is NOT effective after 72 hours — every hour matters**', 'en', 'WHO/BHIVA', 6, true),

('clinical_guideline', 'wound_care', ARRAY['wound','laceration','cut','wound care','tetanus','suture','dressing','infection prevention'], 'Wound Care Guidelines', E'## Wound Care Guidelines\n\n**Assessment:**\n- Mechanism, time since injury\n- Contamination, foreign bodies\n- Neurovascular status distal to wound\n- Tendon/bone involvement\n\n**Management:**\n1. Irrigate with normal saline (copious)\n2. Debride devitalized tissue\n3. Primary closure if <6h (face: up to 24h)\n4. Delayed closure if contaminated or >6h\n\n**Tetanus prophylaxis:**\n- Clean wound: booster if >10 years since last dose\n- Tetanus-prone wound: booster if >5 years + TIG if not fully immunized\n\n**Antibiotic prophylaxis (not routine):**\n- Animal/human bites: co-amoxiclav\n- Contaminated wounds\n- Immunocompromised patients\n\n**Red flags for wound infection:**\n- Increasing pain, redness, swelling after 48h\n- Purulent discharge, fever\n- Red streaking (lymphangitis)\n\n⚠️ **Animal bites: always assess for rabies risk — PEP if indicated**', 'en', 'WHO/NICE', 6, true),

('clinical_guideline', 'burns_management', ARRAY['burns','scald','thermal','burn management','fluid resuscitation','dressing','wound care'], 'Burns Management Guidelines', E'## Burns Management Guidelines\n\n**First aid (20-20-20 rule):**\n- Cool running water for 20 minutes\n- Within 20 minutes of injury\n- Up to 20 hours after injury (still beneficial)\n\n**Assessment:**\n- **Depth:** Superficial (red, painful), Partial (blisters), Full (white/charred, painless)\n- **Area:** Rule of Nines (adult) or palm = 1% TBSA\n\n**Minor burns (<10% TBSA, partial thickness):**\n- Clean, apply paraffin gauze + padding\n- Analgesia, elevate if limb\n- Review in 48 hours\n\n**Major burns (>15% adult, >10% child, or full thickness):**\n- Parkland formula: 4mL × kg × %TBSA\n- Half in first 8h, rest in 16h\n- Ringer''s lactate preferred\n- NG tube, urinary catheter, analgesia\n- Escharotomy if circumferential\n\n**Do NOT:** Apply ice, butter, toothpaste, egg whites\n\n⚠️ **Airway burns: hoarse voice, singed hair → early intubation**', 'en', 'WHO/NICE', 6, true),

('clinical_guideline', 'fracture_first_aid', ARRAY['fracture','broken bone','splint','immobilize','x-ray','orthopedic','cast','first aid'], 'Fracture First Aid & Management', E'## Fracture First Aid & Management\n\n**Suspect fracture if:**\n- Pain, swelling, deformity after trauma\n- Loss of function, crepitus\n- Point tenderness over bone\n\n**First aid:**\n1. Immobilize in position found\n2. Splint (include joint above and below)\n3. Ice pack (wrapped, 20 min on/off)\n4. Elevate, analgesia\n5. Check and document distal neurovascular status (CRT, pulse, sensation, movement)\n\n**Open fracture:**\n- Cover with sterile moist dressing\n- IV antibiotics (co-amoxiclav + gentamicin)\n- Tetanus prophylaxis\n- Photograph wound then cover — do not repeatedly expose\n- Urgent orthopedic referral\n\n**Red flags (vascular compromise):**\n- Absent distal pulse, cold/pale limb\n- Compartment syndrome: pain out of proportion, pain on passive stretch\n\n⚠️ **Compartment syndrome = surgical emergency — fasciotomy within 6 hours**', 'en', 'NICE/BOAST', 6, true),

('clinical_guideline', 'uti_management', ARRAY['uti','urinary tract infection','cystitis','pyelonephritis','dysuria','frequency','antibiotics','urine culture'], 'UTI Management Guidelines', E'## UTI Management Guidelines\n\n**Uncomplicated cystitis (women):**\n- Nitrofurantoin 100mg MR BD for 3 days (first-line)\n- Trimethoprim 200mg BD for 3 days (if low resistance)\n- No urine culture needed for typical presentation\n\n**Complicated UTI / Pyelonephritis:**\n- Urine culture before antibiotics\n- Co-amoxiclav 500/125 TDS for 7 days\n- Or ciprofloxacin 500mg BD for 7 days\n- Consider IV antibiotics if systemically unwell\n\n**UTI in men:** Always complicated — urine culture, 7-14 day course, investigate\n\n**UTI in pregnancy:**\n- Always treat (including asymptomatic bacteriuria)\n- Nitrofurantoin (avoid at term), cefalexin\n- Urine culture at booking\n\n**Recurrent UTI (≥3/year):**\n- Self-start antibiotics\n- Post-coital prophylaxis\n- Consider low-dose prophylaxis\n\n⚠️ **Men with UTI or children with UTI → investigate for underlying cause**', 'en', 'NICE/EAU', 6, true),

('clinical_guideline', 'migraine_management', ARRAY['migraine','headache','aura','triptan','prophylaxis','nausea','photophobia','tension headache'], 'Migraine Management', E'## Migraine Management Guidelines\n\n**Acute treatment (stepwise):**\n1. Simple analgesia: Aspirin 900mg or Ibuprofen 400mg (early)\n2. Add antiemetic: Metoclopramide 10mg or Domperidone 10mg\n3. Triptan: Sumatriptan 50-100mg PO (or 6mg SC, or nasal spray)\n4. Combination: triptan + NSAID\n\n**Triptan rules:**\n- Take early in attack (but after aura resolves)\n- Max 2 doses in 24h, max 9 days/month\n- Contraindicated: IHD, uncontrolled HTN, previous stroke\n\n**Prophylaxis (if ≥4 attacks/month or significant disability):**\n- First-line: Propranolol 40-80mg BD or Topiramate 25-100mg/day\n- Second-line: Amitriptyline 10-75mg at night\n- Candesartan 8-16mg daily\n- Trial for 2-3 months minimum\n\n**Medication overuse headache:**\n- Analgesics >15 days/month or triptans >10 days/month\n- Treatment: withdrawal + prophylaxis\n\n⚠️ **Topiramate is teratogenic — ensure contraception**', 'en', 'NICE/IHS', 6, true),

('clinical_guideline', 'gerd_management', ARRAY['gerd','acid reflux','heartburn','esophagitis','ppi','h2 blocker','dyspepsia','indigestion'], 'GERD Management', E'## GERD Management Guidelines\n\n**Lifestyle modifications:**\n- Weight loss if overweight\n- Elevate head of bed\n- Avoid late meals, tight clothing\n- Reduce: caffeine, alcohol, spicy/fatty foods\n- Stop smoking\n\n**Stepwise treatment:**\n1. Antacids/alginate PRN (mild symptoms)\n2. PPI trial: Omeprazole 20mg daily for 4-8 weeks\n3. Step down to lowest effective dose or H2RA\n4. Long-term PPI only if Barrett''s, severe esophagitis, or recurrent symptoms\n\n**Alarm features (urgent referral):**\n- Dysphagia, weight loss\n- Persistent vomiting\n- GI bleeding (hematemesis/melena)\n- Age >55 with new dyspepsia\n- Anemia\n\n**H. pylori:**\n- Test and treat if dyspepsia without alarm features\n- Triple therapy: PPI + amoxicillin + clarithromycin for 7 days\n\n⚠️ **Alarm symptoms in over-55s → 2-week wait upper GI endoscopy**', 'en', 'NICE/ACG', 6, true),

('symptom_guide', 'abdominal_pain_differential', ARRAY['abdominal pain','stomach pain','belly pain','epigastric','rlq','ruq','lif','flank pain'], 'Abdominal Pain Differentials', E'## Abdominal Pain Differential Diagnosis\n\n**By location:**\n\n**RUQ:** Cholecystitis, hepatitis, biliary colic, pneumonia (referred), peptic ulcer\n**Epigastric:** Peptic ulcer, pancreatitis, GERD, MI (referred), gastritis\n**LUQ:** Splenic pathology, gastric ulcer, pancreatitis (tail), pneumonia\n**RIF/RLQ:** Appendicitis, ovarian cyst, ectopic pregnancy, mesenteric adenitis, Crohn''s\n**LIF/LLQ:** Diverticulitis, ovarian pathology, constipation, IBD, ectopic\n**Suprapubic:** UTI, cystitis, PID, urinary retention\n**Periumbilical:** Early appendicitis, small bowel obstruction, AAA\n**Diffuse:** Peritonitis, bowel obstruction, DKA, IBS, mesenteric ischemia\n\n**Key questions:**\n- Onset (sudden vs gradual), character, radiation\n- Aggravating/relieving factors\n- Associated: fever, vomiting, bowel changes, urinary symptoms\n- LMP (always in women of reproductive age)\n\n⚠️ **Always rule out surgical causes and ectopic pregnancy in reproductive-age women**', 'en', 'Clinical/WHO', 5, true),

('symptom_guide', 'headache_types', ARRAY['headache','migraine','tension headache','cluster headache','red flag headache','thunderclap','temporal arteritis'], 'Headache Types & Differentials', E'## Headache Differential Diagnosis\n\n**Primary headaches:**\n- **Tension:** bilateral, band-like, mild-moderate, no nausea\n- **Migraine:** unilateral, throbbing, moderate-severe, nausea, photo/phonophobia, ± aura\n- **Cluster:** unilateral periorbital, severe, 15-180 min, lacrimation, rhinorrhea, restlessness\n\n**Secondary (red flag) headaches — SNOOP:**\n- **S**ystemic symptoms (fever, weight loss, cancer, HIV)\n- **N**eurological signs (focal deficit, papilledema)\n- **O**nset sudden (thunderclap → SAH until proven otherwise)\n- **O**lder (>50, new onset → temporal arteritis)\n- **P**rogressive, positional, precipitated by Valsalva\n\n**Urgent investigations:**\n- Thunderclap: CT head → LP if CT normal\n- New onset >50: ESR/CRP (temporal arteritis)\n- Papilledema: CT/MRI → LP for idiopathic intracranial hypertension\n\n⚠️ **Thunderclap headache = SAH until proven otherwise — do NOT send home**', 'en', 'NICE/IHS', 5, true),

('symptom_guide', 'joint_pain', ARRAY['joint pain','arthritis','arthralgia','swollen joint','gout','rheumatoid','osteoarthritis','septic arthritis'], 'Joint Pain Differentials', E'## Joint Pain Differential Diagnosis\n\n**Monoarthritis (single joint):**\n- Septic arthritis (hot, swollen, can''t move — EMERGENCY)\n- Gout/pseudogout (crystal arthropathy)\n- Trauma/hemarthrosis\n- Reactive arthritis\n\n**Polyarthritis (multiple joints):**\n- Rheumatoid arthritis (small joints, symmetrical, morning stiffness >30 min)\n- Osteoarthritis (large joints, worse with activity, minimal morning stiffness)\n- Viral arthritis\n- SLE, psoriatic arthritis\n\n**Investigations:**\n- Bloods: FBC, ESR/CRP, uric acid, RF, anti-CCP\n- Joint aspiration: crystal analysis, culture (MUST do if septic suspected)\n- X-ray: joint space narrowing, erosions, chondrocalcinosis\n\n**Red flags (septic arthritis):**\n- Hot, swollen, painful joint + fever\n- Unable to weight-bear or move joint\n- Immunosuppressed or joint prosthesis\n\n⚠️ **Suspected septic arthritis → joint aspiration BEFORE antibiotics**', 'en', 'NICE/BSR', 5, true),

('symptom_guide', 'cough_evaluation', ARRAY['cough','chronic cough','hemoptysis','productive cough','dry cough','wheeze','sputum'], 'Cough Evaluation', E'## Cough Differential Diagnosis\n\n**Acute (<3 weeks):**\n- URTI (most common), influenza, COVID-19\n- Pneumonia, acute bronchitis\n- Asthma exacerbation, PE\n- Foreign body (children)\n\n**Chronic (>8 weeks):**\n- Post-nasal drip/upper airway cough syndrome\n- Asthma/cough-variant asthma\n- GERD\n- ACE inhibitor cough (switch to ARB)\n- COPD, bronchiectasis\n- TB (if >2 weeks + risk factors)\n- Lung cancer (if >45, smoker, hemoptysis)\n\n**Red flags:**\n- Hemoptysis → CXR ± CT (rule out malignancy, TB)\n- Weight loss, night sweats (TB, cancer)\n- Dyspnea, stridor\n- Smoker >45 with new/changed cough\n\n**Approach:**\n1. CXR if >3 weeks or red flags\n2. Stop ACEi if applicable (resolves in 1-4 weeks)\n3. Trial PPI if GERD suspected\n4. Spirometry if asthma/COPD suspected\n\n⚠️ **Hemoptysis in a smoker >40 → urgent 2-week wait referral for lung cancer**', 'en', 'NICE/BTS', 5, true),

('symptom_guide', 'dizziness_vertigo', ARRAY['dizziness','vertigo','lightheaded','spinning','bppv','labyrinthitis','vestibular','nystagmus'], 'Dizziness & Vertigo Differentials', E'## Dizziness & Vertigo Differential Diagnosis\n\n**True vertigo (room spinning):**\n- **BPPV:** brief (<1 min), positional, Dix-Hallpike positive\n  - Treatment: Epley maneuver\n- **Vestibular neuritis:** sudden, severe, days-weeks, no hearing loss\n  - Treatment: vestibular rehabilitation, short-term prochlorperazine\n- **Ménière''s disease:** episodic vertigo + hearing loss + tinnitus + fullness\n  - Treatment: betahistine, low-salt diet\n- **Acoustic neuroma:** gradual unilateral hearing loss + tinnitus + imbalance\n\n**Non-vertiginous dizziness:**\n- Presyncope: orthostatic hypotension, cardiac causes\n- Disequilibrium: medication, neuropathy, elderly\n- Psychogenic: anxiety, hyperventilation\n\n**Red flags (central cause — stroke):**\n- New headache, focal neurology\n- HINTS exam: normal HIT + direction-changing nystagmus + skew deviation\n- Unable to walk, dysarthria\n\n⚠️ **Acute vertigo + HINTS positive for central → urgent stroke pathway**', 'en', 'NICE/ENT', 5, true),

('symptom_guide', 'palpitations', ARRAY['palpitations','heart racing','fast heartbeat','irregular heartbeat','arrhythmia','afib','svt','anxiety'], 'Palpitations Differentials', E'## Palpitations Differential Diagnosis\n\n**Cardiac causes:**\n- Ectopic beats (atrial/ventricular) — most common, usually benign\n- AF (irregular irregular pulse)\n- SVT (sudden onset/offset, fast regular)\n- Ventricular tachycardia (broad complex — dangerous)\n- Structural heart disease\n\n**Non-cardiac causes:**\n- Anxiety, panic attacks (very common)\n- Caffeine, alcohol, drugs\n- Thyrotoxicosis\n- Anemia\n- Fever, dehydration\n- Medications (salbutamol, theophylline)\n\n**Investigations:**\n- 12-lead ECG (capture during episode if possible)\n- Bloods: FBC, TFTs, electrolytes, glucose\n- 24-48h Holter monitor if intermittent\n- Echocardiogram if structural disease suspected\n\n**Red flags:**\n- Syncope with palpitations\n- Family history of sudden cardiac death\n- Palpitations during exercise\n- Associated chest pain or dyspnea\n\n⚠️ **Syncope + palpitations = high risk — urgent cardiology referral**', 'en', 'NICE/ESC', 5, true),

('symptom_guide', 'urinary_symptoms', ARRAY['urinary symptoms','dysuria','frequency','urgency','hematuria','retention','incontinence','prostate'], 'Urinary Symptoms Differentials', E'## Urinary Symptoms Differential Diagnosis\n\n**Dysuria (painful urination):**\n- UTI (most common), STI (urethritis), vaginitis\n- Interstitial cystitis, bladder stone\n\n**Frequency/urgency:**\n- UTI, overactive bladder, diabetes\n- Pregnancy, prostate enlargement (BPH)\n- Anxiety\n\n**Hematuria:**\n- Visible: UTI, stones, malignancy, trauma, glomerulonephritis\n- Non-visible: same + vigorous exercise, menstrual contamination\n- **>45 with visible hematuria → 2-week wait urology referral**\n\n**Urinary retention:**\n- BPH, urethral stricture, medications (anticholinergics)\n- Cauda equina syndrome, diabetic neuropathy\n- Post-surgical, constipation\n\n**Incontinence:**\n- Stress: with cough/sneeze (pelvic floor weakness)\n- Urge: overactive bladder\n- Overflow: chronic retention\n- Functional: mobility/cognitive impairment\n\n⚠️ **Visible hematuria in adults → always investigate for malignancy**', 'en', 'NICE/EAU', 5, true),

('symptom_guide', 'skin_rash', ARRAY['rash','skin rash','dermatitis','eczema','psoriasis','urticaria','fungal','viral rash','drug rash'], 'Skin Rash Differentials', E'## Skin Rash Differential Diagnosis\n\n**Acute/inflammatory:**\n- **Urticaria:** raised, itchy wheals, transient. Cause: allergy, infection, idiopathic\n- **Contact dermatitis:** localized to contact area, itchy, vesicles\n- **Drug rash:** morbilliform (5-14 days after starting drug)\n- **Erythema multiforme:** target lesions (HSV, drugs)\n\n**Chronic:**\n- **Eczema:** itchy, dry, flexural (children), extensor (infants)\n  - Treatment: emollients + topical steroids\n- **Psoriasis:** well-demarcated, silvery scale, extensor surfaces, nails\n  - Treatment: emollients, topical steroids, vitamin D analogues\n\n**Infectious:**\n- **Cellulitis:** spreading erythema, warmth, swelling (bacterial)\n- **Fungal:** ring-shaped (tinea), satellite lesions (candida)\n- **Viral exanthems:** measles, chickenpox, hand-foot-mouth\n- **Scabies:** intense itch (worse at night), burrows, finger webs\n\n**Red flags:**\n- Non-blanching rash + fever (meningococcal)\n- Blistering >30% body (SJS/TEN)\n- Mucosal involvement\n\n⚠️ **Non-blanching rash with fever = meningococcal until proven otherwise**', 'en', 'NICE/BAD', 5, true),

('symptom_guide', 'eye_redness', ARRAY['red eye','conjunctivitis','eye pain','vision loss','uveitis','glaucoma','keratitis','foreign body eye'], 'Red Eye Differentials', E'## Red Eye Differential Diagnosis\n\n**Benign (primary care):**\n- **Conjunctivitis:** diffuse redness, discharge (viral=watery, bacterial=purulent, allergic=itchy)\n- **Subconjunctival hemorrhage:** bright red patch, painless, resolves in 2 weeks\n- **Blepharitis:** lid margin crusting, burning\n\n**Urgent referral:**\n- **Anterior uveitis/iritis:** pain, photophobia, small pupil, ciliary flush\n- **Acute glaucoma:** severe pain, haloes, fixed dilated pupil, hard eye\n- **Keratitis:** pain, photophobia, fluorescein staining positive\n- **Scleritis:** deep boring pain, tender globe, violaceous color\n\n**Key questions:**\n- Pain? (Painless = likely conjunctivitis or SCH)\n- Vision affected? (Yes = urgent)\n- Photophobia? (Yes = uveitis, keratitis)\n- Contact lenses? (Keratitis risk — refer same day)\n\n**Do NOT:**\n- Prescribe steroids (can worsen herpes keratitis)\n- Patch the eye\n- Use topical anesthetic long-term\n\n⚠️ **Contact lens wearer with red, painful eye = urgent ophthalmology referral**', 'en', 'NICE/AAO', 5, true),

('symptom_guide', 'ear_pain', ARRAY['ear pain','otalgia','otitis media','otitis externa','ear infection','hearing loss','ear discharge'], 'Ear Pain Differentials', E'## Ear Pain (Otalgia) Differentials\n\n**Primary (ear origin):**\n- **Otitis media (AOM):** ear pain + fever + bulging TM (common in children)\n  - Management: most resolve without antibiotics (watchful waiting 48-72h)\n  - Antibiotics if: <6 months, bilateral in <2y, perforated TM, systemically unwell\n  - Amoxicillin 40mg/kg/day for 5 days\n- **Otitis externa:** itchy, painful canal, tragal tenderness, discharge\n  - Treatment: ear toilet + topical drops (acetic acid or abx + steroid)\n- **Foreign body, cerumen impaction, TM perforation**\n\n**Referred (non-ear origin):**\n- TMJ dysfunction, dental pathology\n- Pharyngitis, tonsillitis\n- Cervical spine (C2-C3)\n- Rare: laryngeal/pharyngeal cancer (persistent unilateral otalgia)\n\n**Red flags:**\n- Mastoid tenderness/swelling (mastoiditis)\n- Facial nerve palsy\n- Persistent unilateral otalgia (adults) → exclude malignancy\n\n⚠️ **Mastoid swelling + fever + ear pain = mastoiditis → urgent ENT referral + IV antibiotics**', 'en', 'NICE/AAO', 5, true),

('symptom_guide', 'back_pain', ARRAY['back pain','low back pain','lumbar','sciatica','disc herniation','red flag back','spine'], 'Back Pain Differentials', E'## Back Pain Differential Diagnosis\n\n**Mechanical (95%):**\n- Non-specific low back pain (most common)\n- Disc herniation/sciatica\n- Spinal stenosis (neurogenic claudication)\n- Osteoarthritis, spondylosis\n\n**Red flag causes (need urgent investigation):**\n- **Cauda equina:** bilateral sciatica, bladder/bowel dysfunction, saddle numbness\n- **Cancer:** age >50, history of cancer, weight loss, night pain\n- **Infection:** fever, IV drug use, immunosuppressed, recent surgery\n- **Fracture:** significant trauma, osteoporosis, steroid use\n- **AAA:** abdominal pulsating mass, cardiovascular risk factors\n\n**Management (non-specific):**\n- Reassure, stay active (bed rest is harmful)\n- NSAIDs first-line analgesia\n- Physical therapy\n- Avoid imaging unless red flags\n- Review in 6 weeks if not improving\n\n**Sciatica:** pain radiating below knee, positive straight leg raise\n- Conservative for 6-8 weeks\n- MRI + surgical referral if persistent or progressive deficit\n\n⚠️ **Cauda equina = emergency MRI + surgical decompression**', 'en', 'NICE/WHO', 5, true),

('symptom_guide', 'weight_loss', ARRAY['weight loss','unintentional weight loss','cachexia','appetite loss','cancer screening','thyroid'], 'Unintentional Weight Loss Differentials', E'## Unintentional Weight Loss Differentials\n\n**Definition:** >5% body weight in 6-12 months without trying\n\n**Malignancy:**\n- GI cancers, lung cancer, lymphoma\n- Any advanced malignancy\n\n**Endocrine:**\n- Hyperthyroidism, diabetes (uncontrolled)\n- Adrenal insufficiency\n\n**GI:**\n- Malabsorption (celiac, IBD, pancreatic insufficiency)\n- Peptic ulcer, chronic liver disease\n\n**Psychiatric:**\n- Depression (most common cause in elderly)\n- Eating disorders, anxiety\n\n**Infection:**\n- TB, HIV, chronic infections\n- Parasitic infections\n\n**Other:**\n- Heart failure, COPD\n- Medications, substance abuse\n- Social (poverty, isolation)\n\n**Workup:**\n- Bloods: FBC, ESR/CRP, TFTs, HbA1c, LFTs, renal, calcium, HIV\n- Urine dipstick\n- CXR\n- Age-appropriate cancer screening\n- Celiac serology (tTG)\n\n⚠️ **Unexplained weight loss in >50 → malignancy until proven otherwise**', 'en', 'NICE', 5, true),

('symptom_guide', 'fatigue', ARRAY['fatigue','tiredness','exhaustion','lethargy','chronic fatigue','tired all the time','tatt'], 'Fatigue Differentials', E'## Fatigue Differential Diagnosis\n\n**"Tired All The Time" (TATT) — systematic approach:**\n\n**Hematological:** Iron deficiency anemia (most common organic cause)\n\n**Endocrine:**\n- Hypothyroidism, diabetes\n- Adrenal insufficiency\n- Vitamin D deficiency\n\n**Psychological (most common overall):**\n- Depression, anxiety\n- Sleep disorders (insomnia, OSA)\n- Stress, burnout\n\n**Chronic disease:**\n- Heart failure, COPD, CKD\n- Chronic liver disease\n- Malignancy\n\n**Infection:** EBV/post-viral, HIV, TB, hepatitis\n\n**Lifestyle:** Poor sleep, sedentary, alcohol, medications (beta-blockers, antihistamines)\n\n**Workup (minimum):**\n- FBC, ferritin, TFTs, HbA1c\n- U&Es, LFTs, calcium, vitamin D\n- ESR/CRP\n- Urinalysis, celiac screen (tTG)\n- PHQ-9 depression screening\n\n**Chronic Fatigue Syndrome:** >3 months unexplained fatigue + PEM + cognitive dysfunction\n\n⚠️ **Always screen for depression — most common cause of chronic fatigue in primary care**', 'en', 'NICE', 5, true),

('symptom_guide', 'edema_swelling', ARRAY['edema','swelling','ankle swelling','pitting edema','fluid retention','leg swelling','ascites','lymphedema'], 'Edema/Swelling Differentials', E'## Edema Differential Diagnosis\n\n**Unilateral leg swelling:**\n- **DVT** (urgent — see DVT/PE red flags)\n- Cellulitis (red, warm, painful)\n- Lymphedema (non-pitting, chronic)\n- Baker''s cyst rupture (behind knee)\n- Compartment syndrome (post-injury)\n\n**Bilateral leg swelling:**\n- Heart failure (with JVD, dyspnea)\n- Liver cirrhosis (with ascites, jaundice)\n- Nephrotic syndrome (with proteinuria, hypoalbuminemia)\n- Venous insufficiency (chronic, varicose veins)\n- Medications (CCBs — amlodipine, NSAIDs, steroids)\n- Pregnancy (physiological or pre-eclampsia)\n\n**Generalized edema (anasarca):**\n- Nephrotic syndrome, liver failure\n- Heart failure, severe malnutrition\n\n**Investigations:**\n- Bloods: albumin, LFTs, renal function, BNP\n- Urine: protein/creatinine ratio\n- Duplex USS if DVT suspected\n- Echo if heart failure suspected\n\n⚠️ **Unilateral painful leg swelling = DVT until proven otherwise**', 'en', 'NICE/Clinical', 5, true),

('symptom_guide', 'chest_pain_differentials', ARRAY['chest pain','cardiac','musculoskeletal','pleuritic','costochondritis','gerd chest','anxiety chest'], 'Chest Pain Differentials', E'## Chest Pain Differential Diagnosis\n\n**Cardiac:**\n- ACS (MI/unstable angina): crushing, central, radiating, with sweating\n- Stable angina: exertional, relieved by rest/GTN\n- Pericarditis: sharp, pleuritic, relieved sitting forward\n- Aortic dissection: tearing, radiating to back\n\n**Respiratory:**\n- PE: sudden pleuritic pain + dyspnea + tachycardia\n- Pneumothorax: sudden, unilateral, pleuritic\n- Pneumonia: pleuritic + cough + fever\n- Pleuritis: sharp, worse on inspiration\n\n**GI:**\n- GERD: burning, retrosternal, worse lying down, relieved by antacids\n- Esophageal spasm: can mimic cardiac pain\n\n**Musculoskeletal:**\n- Costochondritis: localized, reproducible on palpation\n- Muscle strain\n\n**Other:**\n- Anxiety/panic attack (diagnosis of exclusion)\n- Herpes zoster (dermatomal, preceding rash)\n\n**Approach:** ECG + troponin for all undifferentiated chest pain\n\n⚠️ **Always assume cardiac until proven otherwise — missed MI is a leading cause of malpractice**', 'en', 'NICE/AHA', 5, true);
